    margin: 12px;\r\n}\r\n\r\n.pswp__preloader--active {\r\n    opacity: 1;\r\n}\r\n\r\n.pswp__preloader--active .pswp__preloader__icn {\r\n    background: url(\"../images/preloader.gif\") 0 0 no-repeat;\r\n}\r\n\r\n.pswp--css_animation .pswp__preloader--active {\r\n    opacity: 1;\r\n}\r\n\r\n.pswp--css_animation .pswp__preloader--active .pswp__preloader__icn {\r\n    animation: clockwise 500ms linear infinite;\r\n}\r\n\r\n.pswp--css_animation .pswp__preloader--active .pswp__preloader__donut {\r\n    animation: donut-rotate 1000ms cubic-bezier(0.4, 0, 0.22, 1) infinite;\r\n}\r\n\r\n.pswp--css_animation .pswp__preloader__icn {\r\n    position: absolute;\r\n    top: 15px;\r\n    left: 15px;\r\n    width: 14px;\r\n    height: 14px;\r\n    margin: 0;\r\n    background: none;\r\n    opacity: 0.75;\r\n}\r\n\r\n.pswp--css_animation .pswp__preloader__cut {\r\n    position: relative;\r\n    width: 7px;\r\n    height: 14px;\r\n    overflow: hidden;\r\n}\r\n\r\n.pswp--css_animation .pswp__preloader__donut {\r\n    position: absolute;\r\n    top: 0;\r\n    left: 0;\r\n    box-sizing: border-box;\r\n    width: 14px;\r\n    height: 14px;\r\n    margin: 0;\r\n    background: none;\r\n    border: 2px solid #fff;\r\n    border-bottom-color: transparent;\r\n    border-left-color: transparent;\r\n    border-radius: 50%;\r\n}\r\n\r\n@media screen and (max-width: 1024px) {\r\n    .pswp__preloader {\r\n        position: relative;\r\n        top: auto;\r\n        left: auto;\r\n        float: right;\r\n        margin: 0;\r\n    }\r\n}\r\n\r\n@keyframes clockwise {\r\n    0% {\r\n        transform: rotate(0deg);\r\n    }\r\n\r\n    100% {\r\n        transform: rotate(360deg);\r\n    }\r\n}\r\n\r\n@keyframes donut-rotate {\r\n    0% {\r\n        transform: rotate(0);\r\n    }\r\n\r\n    50% {\r\n        transform: rotate(-140deg);\r\n    }\r\n\r\n    100% {\r\n        transform: rotate(0);\r\n    }\r\n}\r\n\r\n.pswp__ui {\r\n    z-index: 1550;\r\n    visibility: visible;\r\n    opacity: 1;\r\n    -webkit-font-smoothing: auto;\r\n}\r\n\r\n.pswp__top-bar {\r\n    position: absolute;\r\n    top: 0;\r\n    left: 0;\r\n    width: 100%;\r\n    height: 44px;\r\n}\r\n\r\n.pswp__caption,\r\n.pswp__top-bar,\r\n.pswp--has_mouse .pswp__button--arrow--left,\r\n.pswp--has_mouse .pswp__button--arrow--right {\r\n    backface-visibility: hidden;\r\n    transition: opacity 333ms cubic-bezier(0.4, 0, 0.22, 1);\r\n    will-change: opacity;\r\n}\r\n\r\n.pswp--has_mouse .pswp__button--arrow--left,\r\n.pswp--has_mouse .pswp__button--arrow--right {\r\n    visibility: visible;\r\n}\r\n\r\n.pswp__ui--idle .pswp__top-bar {\r\n    opacity: 0;\r\n}\r\n\r\n.pswp__ui--idle .pswp__button--arrow--left,\r\n.pswp__ui--idle .pswp__button--arrow--right {\r\n    opacity: 0;\r\n}\r\n\r\n.pswp__ui--hidden .pswp__top-bar,\r\n.pswp__ui--hidden .pswp__caption,\r\n.pswp__ui--hidden .pswp__button--arrow--left,\r\n.pswp__ui--hidden .pswp__button--arrow--right {\r\n    opacity: 0.001;\r\n}\r\n\r\n.pswp__ui--one-slide .pswp__button--arrow--left,\r\n.pswp__ui--one-slide .pswp__button--arrow--right,\r\n.pswp__ui--one-slide .pswp__counter {\r\n    display: none;\r\n}\r\n\r\n.pswp__element--disabled {\r\n    display: none !important;\r\n}\r\n\r\n.pswp--minimal--dark .pswp__top-bar {\r\n    background: none;\r\n}\r\n\r\n/*\r\n\r\nHey! You reached the end.\r\n\r\nHope you enjoyed this CSS file, if you have any suggestions\r\nfor improvements that might be useful for everyone who uses\r\nthis theme, you can find the open source repository for it\r\nhere: https://github.com/tryghost/casper\r\n\r\nOr, if you've just scrolled all the way to the bottom of the\r\nfile to add some of your own styles. Well, you've come to\r\nthe right place. Onward!\r\n\r\n */\r\n","/* ============================================================\r\n   custom.css — miuh-ghost-theme\r\n   Customizations for michaeluhrich.xyz\r\n   ============================================================\r\n\r\n   Concatenated after screen.css via gulp-concat in gulpfile.js.\r\n   Overrides Casper defaults by cascade position.\r\n\r\n   1. Custom Properties\r\n   2. Global (Body, Selection, Typography)\r\n   3. Header (Dark Editorial)\r\n   4. Post Feed & Cards\r\n   5. Article Content\r\n   6. Footer\r\n   7. Dark Mode\r\n   ============================================================ */\r\n\r\n\r\n/* 1. Custom Properties\r\n/* ---------------------------------------------------------- */\r\n\r\n:root {\r\n    /* Colors — Old paper palette */\r\n    --color-lightgrey: #f4f1eb;\r\n    --color-body-bg: #f4f1eb;\r\n    --color-header-footer: #1a1714;\r\n    --color-logo: #f4f1eb;\r\n    --color-nav-link: #f4f1eb;\r\n    --color-nav-divider: rgba(255, 255, 255, 0.06);\r\n\r\n    /* Dark mode — warm paper palette (overrides Casper cold #151719) */\r\n    --color-darkmode: #1e1b17;\r\n\r\n    /* Header/Footer — Dark Editorial */\r\n    --hf-accent: #99582a;\r\n    --hf-text-dim: rgba(244, 241, 235, 0.6);\r\n\r\n    /* Fonts — Three voices */\r\n    --font-serif: \"Iowan Old Style\", \"Palatino Linotype\", Palatino, \"Book Antiqua\", Georgia, \"Times New Roman\", serif;\r\n    --font-mono: \"SF Mono\", \"Fira Code\", Menlo, Consolas, \"Courier New\", monospace;\r\n}\r\n\r\n\r\n/* 2. Global\r\n/* ---------------------------------------------------------- */\r\n\r\nbody {\r\n    background: var(--color-body-bg, #f4f1eb);\r\n}\r\n\r\n::selection {\r\n    background: rgba(25, 140, 255, 0.25);\r\n    color: inherit;\r\n}\r\n\r\nh1, h2, h3, h4, h5, h6 {\r\n    font-family: var(--gh-font-heading, var(--font-serif));\r\n}\r\n\r\n@media (max-width: 600px) {\n    h2 { font-size: 2.4rem; }\n    h3 { font-size: 2.0rem; }\n}\n\n/* Homepage hero spacing: slightly tighter top/bottom rhythm */\n.home-template .site-header-content:not(.left-aligned):not(.no-content) {\n    padding-top: calc(16vmin + 44px);\n    padding-bottom: 15vmin;\n}\n\n.home-template.has-cover .site-header-content:not(.left-aligned):not(.no-content) {\n    min-height: 500px;\n}\n\n@media (max-width: 991px) {\n    .home-template .site-header-content:not(.left-aligned):not(.no-content) {\n        padding-top: calc(16vmin + 32px);\n        padding-bottom: 14vmin;\n    }\n}\n\n@media (max-width: 767px) {\n    .home-template .site-header-content:not(.left-aligned):not(.no-content) {\n        padding-top: calc(14vmin + 32px);\n        padding-bottom: 12vmin;\n    }\n\n    .home-template.has-cover .site-header-content:not(.left-aligned):not(.no-content) {\n        min-height: 220px;\n    }\n}\n\r\n\r\n/* 3. Header — Dark Editorial\r\n/* ---------------------------------------------------------- */\r\n\r\n.gh-head {\r\n    background-color: var(--color-header-footer);\r\n    color: #fff;\r\n    z-index: 150;\r\n    position: relative;\r\n    box-shadow: 0 1px 0 0 rgba(153, 88, 42, 0.15);\r\n}\r\n\r\n/* Scanlines — barely visible, texture only */\r\n.gh-head::after {\r\n    content: '';\r\n    position: absolute;\r\n    inset: 0;\r\n    background: repeating-linear-gradient(\r\n        0deg,\r\n        rgba(0, 0, 0, 0.03) 0px,\r\n        rgba(0, 0, 0, 0.03) 1px,\r\n        transparent 1px,\r\n        transparent 3px\r\n    );\r\n    pointer-events: none;\r\n    z-index: 10;\r\n}\r\n\r\n/* Logo */\r\n.gh-head-logo {\r\n    font-family: var(--gh-font-heading, var(--font-serif));\r\n    font-weight: 800;\r\n    color: var(--color-logo);\r\n    letter-spacing: -0.01em;\r\n    position: relative;\r\n    display: inline-block;\r\n    text-shadow: none;\r\n    transition: text-shadow 0.3s ease;\r\n}\r\n\r\n.gh-head-logo:hover {\r\n    color: var(--color-logo);\r\n    text-shadow: 0 0 12px rgba(153, 88, 42, 0.6), 0 0 30px rgba(153, 88, 42, 0.25);\r\n}\r\n\r\n.has-cover .gh-head-logo {\r\n    color: var(--color-logo);\r\n}\r\n\r\n/* Navigation */\r\n.gh-head-menu {\r\n    font-family: var(--font-sans);\r\n    font-weight: 400;\r\n}\r\n\r\n.gh-head-menu .nav a {\r\n    color: var(--hf-text-dim);\r\n    text-transform: uppercase;\r\n    letter-spacing: 0.04em;\r\n    font-size: 1.3rem;\r\n    position: relative;\r\n    transition: color 0.2s ease;\r\n}\r\n\r\n/* Accent underline on hover */\r\n.gh-head-menu .nav a::after {\r\n    content: '';\r\n    position: absolute;\r\n    bottom: -4px;\r\n    left: 0;\r\n    width: 0;\r\n    height: 1px;\r\n    background: var(--hf-accent);\r\n    transition: width 0.3s ease;\r\n}\r\n\r\n.gh-head-menu .nav a:hover {\r\n    color: var(--color-nav-link);\r\n    opacity: 1;\r\n}\r\n\r\n.gh-head-menu .nav a:hover::after {\r\n    width: 100%;\r\n}\r\n\r\n/* Nav blink fix */\r\n@media (min-width: 992px) {\r\n    body:not(.is-dropdown-loaded) .gh-head-menu .nav > li {\r\n        opacity: 1;\r\n    }\r\n}\r\n\r\n/* Stacked header dividers */\r\n.is-head-stacked .gh-head-menu::before,\r\n.is-head-stacked .gh-head-menu::after {\r\n    background-color: var(--color-nav-divider);\r\n}\r\n\r\n.is-head-stacked.has-cover .gh-head-menu::before,\r\n.is-head-stacked.has-cover .gh-head-menu::after {\r\n    background-color: var(--color-nav-divider);\r\n}\r\n\r\n/* Actions — Sign in / Subscribe */\r\n.gh-head-link:hover {\r\n    color: var(--color-body-bg);\r\n}\r\n\r\n.gh-head-actions a:not([class*=\"gh-button\"]) {\r\n    text-transform: uppercase;\r\n    letter-spacing: 0.03em;\r\n    color: var(--hf-text-dim);\r\n    transition: color 0.2s ease;\r\n}\r\n\r\n.gh-head-actions a:not([class*=\"gh-button\"]):hover {\r\n    color: var(--color-nav-link);\r\n}\r\n\r\n.gh-head-button {\r\n    background: transparent;\r\n    border: 1px solid rgba(153, 88, 42, 0.75);\r\n    color: var(--hf-text-dim);\r\n    text-transform: uppercase;\r\n    letter-spacing: 0.04em;\r\n    transition: border-color 0.2s ease, color 0.2s ease, background 0.2s ease;\r\n}\r\n\r\n.gh-head-button:hover {\r\n    border-color: rgba(153, 88, 42, 0.85);\r\n    color: var(--color-nav-link);\r\n}\r\n\r\n.has-cover .gh-head-button {\r\n    background: transparent;\r\n    border: 1px solid rgba(153, 88, 42, 0.75);\r\n    color: var(--hf-text-dim);\r\n}\r\n\r\n/* Search */\r\n.gh-search {\r\n    color: var(--hf-text-dim);\r\n}\r\n\r\n.gh-search:hover {\r\n    color: var(--color-nav-link);\r\n    opacity: 1;\r\n}\r\n\r\n/* Burger */\r\n.gh-burger::before,\r\n.gh-burger::after {\r\n    background-color: rgba(244, 241, 235, 0.7);\r\n}\r\n\r\n.has-cover .gh-burger::before,\r\n.has-cover .gh-burger::after {\r\n    background-color: rgba(244, 241, 235, 0.7);\r\n}\r\n\r\n/* Desktop: consistent header font sizes */\r\n@media (min-width: 992px) {\r\n    .gh-head-actions a:not([class*=\"gh-button\"]) {\r\n        font-size: 1.3rem;\r\n    }\r\n    .gh-head-actions .gh-button {\r\n        font-size: 1.3rem;\r\n    }\r\n}\r\n\r\n/* Mobile */\r\n@media (max-width: 767px) {\n    #gh-head .gh-head-logo {\n        font-size: 2.2rem;\n    }\n\n    #gh-head .nav a {\n        font-size: 2.2rem;\n    }\n\n    #gh-head .gh-head-button {\n        font-size: 1.6rem;\n        text-transform: uppercase;\n    }\n\n    #gh-head .gh-head-link {\n        font-size: 1.5rem;\n    }\n\r\n    .gh-head-open.has-cover #gh-head,\r\n    .gh-head-open.has-cover #gh-head .gh-head-actions {\r\n        background-color: var(--color-header-footer);\r\n    }\r\n\r\n    .gh-head-open #gh-head .gh-head-actions {\n        background-color: var(--color-header-footer);\n    }\n}\n\r\n\r\n/* 4. Post Feed & Cards\r\n/* ---------------------------------------------------------- */\r\n\r\n.home-template .site-description:first-child,\n.home-template :is(.site-logo, .site-title) + .site-description {\n    font-family: var(--gh-font-heading, var(--font-mono));\n    max-width: 1100px;\n    margin-right: auto;\n    margin-left: auto;\n    font-size: 4.8rem;\n    line-height: 1.12;\n    text-align: center;\n    text-wrap: balance;\n}\n\n.home-template .site-subheadline {\n    margin: 14px auto 0;\n    max-width: 980px;\n    font-family: var(--gh-font-heading, var(--font-serif));\n    font-size: 2.05rem;\n    font-weight: 500;\n    letter-spacing: 0.02em;\n    line-height: 1.45;\n    text-align: center;\n    text-wrap: pretty;\n    color: inherit;\n    opacity: 0.78;\n}\n\n@media (max-width: 767px) {\n    .home-template .site-description:first-child,\n    .home-template :is(.site-logo, .site-title) + .site-description {\n        max-width: 92vw;\n        font-size: 2.8rem !important;\n        line-height: 1.2;\n    }\n\n    .home-template .site-subheadline {\n        max-width: 92vw;\n        margin-top: 8px;\n        font-size: 1.7rem;\n        line-height: 1.45;\n    }\n}\n\n.post-card-excerpt {\n    font-family: var(--gh-font-body, var(--font-serif));\n    letter-spacing: 0.01em;\n}\n\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .post-card-excerpt {\r\n    font-family: var(--gh-font-body, var(--font-serif));\r\n}\r\n\r\n/* Mono for meta information */\r\n.post-card-tags,\r\n.post-card-meta,\r\n.article-tag a,\r\n.byline-meta-content {\r\n    font-family: var(--font-mono);\r\n    font-size: 1.4rem;\r\n    letter-spacing: 0.02em;\r\n    text-transform: uppercase;\r\n}\r\n\r\n\r\n/* 5. Article Content\r\n/* ---------------------------------------------------------- */\r\n\r\n.gh-content > blockquote:not([class]),\r\n.gh-content > ol,\r\n.gh-content > ul,\r\n.gh-content > dl,\r\n.gh-content > p {\r\n    font-family: var(--gh-font-body, var(--font-mono));\r\n    letter-spacing: -0.02em;\r\n    word-spacing: -0.02em;\r\n}\r\n\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content > blockquote,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content > ol,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content > ul,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content > dl,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content > p,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content .kg-callout-card .kg-callout-text,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content .kg-toggle-card .kg-toggle-content > ol,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content .kg-toggle-card .kg-toggle-content > ul,\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .gh-content .kg-toggle-card .kg-toggle-content > p {\r\n    font-family: var(--gh-font-body, var(--font-mono));\r\n}\r\n\r\n.has-sans-body:not([class*=\" gh-font-body\"]):not([class^=\"gh-font-body\"]) .kg-blockquote-alt {\r\n    font-family: var(--gh-font-body, var(--font-mono));\r\n}\r\n\r\n@media (max-width: 650px) {\n    .gh-content > blockquote:not([class]),\r\n    .gh-content > ol,\r\n    .gh-content > ul,\r\n    .gh-content > dl,\r\n    .gh-content > p,\r\n    .gh-content .kg-callout-card .kg-callout-text,\r\n    .gh-content .kg-toggle-card .kg-toggle-content > ol,\r\n    .gh-content .kg-toggle-card .kg-toggle-content > ul,\r\n    .gh-content .kg-toggle-card .kg-toggle-content > p {\r\n        font-family: var(--gh-font-body, var(--font-mono));\r\n        letter-spacing: -0.02em;\r\n        word-spacing: -0.02em;\r\n    }\r\n\r\n    .gh-content .kg-product-card .kg-product-card-description > p,\r\n    .gh-content .kg-product-card .kg-product-card-description > ol,\r\n    .gh-content .kg-product-card .kg-product-card-description > ul {\r\n        font-family: var(--gh-font-body, var(--font-mono));\r\n        letter-spacing: -0.02em;\r\n        word-spacing: -0.02em;\r\n    }\r\n}\n\n@media (max-width: 767px) {\n    .post-template .gh-content > h3 {\n        font-size: 2.2rem;\n    }\n}\n\n\n/* 6. Footer\n/* ---------------------------------------------------------- */\n\r\n.site-footer {\r\n    background: var(--color-header-footer);\r\n    position: relative;\r\n    border-top: 1px solid var(--color-nav-divider);\r\n}\r\n\r\n/* Scanlines */\r\n.site-footer::after {\r\n    content: '';\r\n    position: absolute;\r\n    inset: 0;\r\n    background: repeating-linear-gradient(\r\n        0deg,\r\n        rgba(0, 0, 0, 0.03) 0px,\r\n        rgba(0, 0, 0, 0.03) 1px,\r\n        transparent 1px,\r\n        transparent 3px\r\n    );\r\n    pointer-events: none;\r\n    z-index: 1;\r\n}\r\n\r\n.site-footer .inner {\r\n    grid-template-columns: 1fr 1fr 1fr;\r\n    color: var(--color-body-bg);\r\n}\r\n\r\n.site-footer-nav li:not(:first-child) a::before {\r\n    background: rgba(255, 255, 255, 0.2);\r\n}\r\n\r\n.site-footer a {\r\n    transition: color 0.2s ease;\r\n}\r\n\r\n/* Mobile: single-column footer, hide dot separators */\r\n@media (max-width: 767px) {\r\n    .site-footer .inner {\r\n        grid-template-columns: 1fr;\r\n    }\r\n\r\n    .site-footer-nav li:not(:first-child) a::before {\r\n        display: none;\r\n    }\r\n}\r\n\r\n\r\n/* 7. Dark Mode\r\n/* ---------------------------------------------------------- */\r\n\r\nhtml.dark-mode body {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode body .gh-head,\r\nhtml.dark-mode body:not(.has-cover) .gh-head {\r\n    background: var(--color-header-footer);\r\n    color: #fff;\r\n}\r\n\r\nhtml.dark-mode .gh-burger::before,\r\nhtml.dark-mode .gh-burger::after {\r\n    background-color: rgba(244, 241, 235, 0.7);\r\n}\r\n\r\nhtml.dark-mode .post-card-featured {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode .post-card-title {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode .pagination a {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode .author-profile-location {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode .article-title {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode .article-byline-meta .author-name a {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\nhtml.dark-mode .footer-cta-title {\r\n    color: rgba(255, 255, 255, 0.85);\r\n}\r\n\r\n/* Tags/dates — override Casper :is() l(-22%) which makes them too dark.\r\n   Must use :is() to match Casper's specificity (0,2,1 from .pagination .page-number) */\r\nhtml.dark-mode :is(.post-card-tags, .post-card-meta, .article-tag a, .byline-meta-content, .pagination .page-number) {\r\n    color: rgba(255, 255, 255, 0.6);\r\n}\r\n\r\nhtml.dark-mode .footer-cta-button {\r\n    background: #36312b;\r\n    border-color: #413b34;\r\n}\r\n\r\nhtml.dark-mode .site-footer {\r\n    background: var(--color-header-footer);\r\n}\r\n\r\n@media (max-width: 767px) {\r\n    html.dark-mode .gh-head-open #gh-head,\r\n    html.dark-mode .gh-head-open:not(.has-cover) #gh-head,\r\n    html.dark-mode .gh-head-open #gh-head .gh-head-actions,\r\n    html.dark-mode .gh-head-open:not(.has-cover) #gh-head .gh-head-actions {\r\n        background: var(--color-header-footer);\r\n    }\r\n}\r\n\r\n\r\n/* 7b. Auto Color (prefers-color-scheme: dark)\r\n/* ---------------------------------------------------------- */\r\n\r\n@media (prefers-color-scheme: dark) {\r\n    html.auto-color body {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color body .gh-head,\r\n    html.auto-color body:not(.has-cover) .gh-head {\r\n        background: var(--color-header-footer);\r\n        color: #fff;\r\n    }\r\n\r\n    html.auto-color .gh-burger::before,\r\n    html.auto-color .gh-burger::after {\r\n        background-color: rgba(244, 241, 235, 0.7);\r\n    }\r\n\r\n    html.auto-color .post-card-featured {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color .post-card-title {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color .pagination a {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color .author-profile-location {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color .article-title {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color .article-byline-meta .author-name a {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    html.auto-color .footer-cta-title {\r\n        color: rgba(255, 255, 255, 0.85);\r\n    }\r\n\r\n    /* Tags/dates — override Casper :is() l(-22%), must match specificity */\r\n    html.auto-color :is(.post-card-tags, .post-card-meta, .article-tag a, .byline-meta-content, .pagination .page-number) {\r\n        color: rgba(255, 255, 255, 0.6);\r\n    }\r\n\r\n    html.auto-color .footer-cta-button {\r\n        background: #36312b;\r\n        border-color: #413b34;\r\n    }\r\n\r\n    html.auto-color .site-footer {\r\n        background: var(--color-header-footer);\r\n    }\r\n\r\n    @media (max-width: 767px) {\r\n        html.auto-color .gh-head-open #gh-head,\r\n        html.auto-color .gh-head-open:not(.has-cover) #gh-head,\r\n        html.auto-color .gh-head-open #gh-head .gh-head-actions,\r\n        html.auto-color .gh-head-open:not(.has-cover) #gh-head .gh-head-actions {\r\n            background: var(--color-header-footer);\r\n        }\r\n    }\r\n}\r\n"]}
